--
-- Table structure for table `dsa`
--

CREATE TABLE `dsa` (
  `iDsaId` int(11) NOT NULL,
  `name` varchar(222) NOT NULL,
  `dsa_code` int(11) NOT NULL,
  `email` varchar(222) NOT NULL,
  `phone` varchar(222) NOT NULL,
  `address` varchar(222) NOT NULL,
  `account_name` varchar(222) NOT NULL,
  `bank_name` varchar(222) NOT NULL,
  `account_number` varchar(222) NOT NULL,
  `ifsc_code` varchar(222) NOT NULL,
  `pan_number` varchar(222) NOT NULL,
  `our_branch` varchar(111) NOT NULL,
  `broker_payout` varchar(222) NOT NULL DEFAULT '0',
  `schemes_type` varchar(222) NOT NULL,
  `scheme_name` varchar(222) NOT NULL,
  `username` varchar(222) NOT NULL,
  `password` varchar(222) NOT NULL,
  `active` varchar(222) NOT NULL,
  `date` datetime NOT NULL,
  `commission_password` varchar(222) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;

